function extraSubjects(area,known){const seen=new Set((known||[]).map(normalizeLabel)),out=[];for(const u of state.units){const n=u.manifest.navigation||{};if(normalizeLabel(n.area)!==normalizeLabel(area)||!n.subject||seen.has(normalizeLabel(n.subject)))continue;seen.add(normalizeLabel(n.subject));out.push({title:n.subject,route:`library-subject/${encodeURIComponent(n.area||'')}/${encodeURIComponent(n.subject||'')}`})}return out.sort((a,b)=>a.title.localeCompare(b.title,'de'))}
