 if(!storage){state.storage={supported:false,persisted:false,usage:0,quota:0};return state.storage}
 let persisted=false,estimate={usage:0,quota:0};
 try{if(storage.persisted)persisted=await storage.persisted()}catch(_e){}
 try{if(storage.estimate)estimate=await storage.estimate()}catch(_e){}
