 async bytes(n){const e=this.entries.get(n);if(!e)throw new Error('Datei fehlt: '+n);if(e.flags&1)throw new Error('Verschlüsselte ZIP-Dateien werden nicht unterstützt.');const v=this.view,p=e.localOffset;if(v.getUint32(p,true)!==0x04034b50)throw new Error('Lokaler ZIP-Header beschädigt: '+n);const nl=v.getUint16(p+26,true),xl=v.getUint16(p+28,true),start=p+30+nl+xl,comp=new Uint8Array(this.buffer,start,e.compressedSize);let out;if(e.method===0)out=new Uint8Array(comp);else if(e.method===8){if(!('DecompressionStream'in window))throw new Error('Der Browser unterstützt die lokale ZIP-Dekompression nicht. Bitte Chrome, Edge oder einen aktuellen Chromium-Browser verwenden.');const st=new Blob([comp]).stream().pipeThrough(new DecompressionStream('deflate-raw'));out=new Uint8Array(await new Response(st).arrayBuffer())}else throw new Error('Nicht unterstützte ZIP-Kompression: '+e.method);if(out.byteLength!==e.uncompressedSize)throw new Error('Dateigröße stimmt nach dem Entpacken nicht: '+n);if(crc32(out)!==e.crc)throw new Error('CRC-Prüfung fehlgeschlagen: '+n);return out}
