function regularCrumbs(u){const c=regularContext(u),out=[{label:'Hauptmenü',path:'home'}];if(c.areaId)out.push({label:c.areaTitle,path:`school/${c.areaId}`});else out.push({label:c.areaTitle,path:`library-area/${encodeURIComponent(c.areaTitle)}`});if(c.subjectId)out.push({label:c.subjectTitle,path:`subject/${c.areaId}/${c.subjectId}`});else out.push({label:c.subjectTitle,path:`library-subject/${encodeURIComponent(c.areaTitle)}/${encodeURIComponent(c.subjectTitle)}`});if(c.levelTitle)out.push({label:c.levelTitle,path:c.levelId?`year/${c.areaId}/${c.subjectId}/${c.levelId}`:`library-level/${encodeURIComponent(c.areaTitle)}/${encodeURIComponent(c.subjectTitle)}/${encodeURIComponent(c.levelTitle)}`});return out}
