function stripText(html){const doc=new DOMParser().parseFromString(String(html||''),'text/html');return(doc.body?.textContent||'').replace(/\s+/g,' ').trim()}
function parseClassroomPhases(l){
 const html=l?.sections?.sequence||'';
 const doc=new DOMParser().parseFromString(html,'text/html');
 const rows=[...doc.querySelectorAll('table tr')].slice(1),phases=[];
 for(const row of rows){const cells=[...row.querySelectorAll('td')].map(x=>x.textContent.replace(/\s+/g,' ').trim());if(cells.length<2)continue;const match=cells[0].match(/(\d+)\s*[–-]\s*(\d+)/);if(!match)continue;phases.push({start:Number(match[1]),end:Number(match[2]),duration:Math.max(1,Number(match[2])-Number(match[1])),name:cells[1]||'Phase',teacher:cells[2]||'',students:cells[3]||'',material:cells[4]||'',note:cells[5]||''})}
 if(!phases.length){const duration=Number(l?.ref?.duration||45);phases.push({start:0,end:duration,duration,name:'Unterricht',teacher:'',students:'',material:'',note:''})}
 return phases
}
function classroomNotausstieg(l){const text=stripText(l?.sections?.help||'')+' '+stripText(l?.sections?.sequence||'');const m=text.match(/Notausstieg:\s*(.*?)(?:Minimalfahrplan:|$)/i),mini=text.match(/Minimalfahrplan:\s*(.*?)(?:$)/i);return{notausstieg:(m?.[1]||'Auf die zentrale Sicherung fokussieren und die individuelle Lernkontrolle beibehalten.').trim(),minimal:(mini?.[1]||'Einstieg – Kernaufgabe – Sicherung – kurzer Abschluss.').trim()}}
function classroomView(uid,lid,h){
 const u=unit(uid),l=lesson(u,lid);if(!u||!l)return h.notFound();const phases=parseClassroomPhases(l),fallback=classroomNotausstieg(l),hasPresentation=Boolean(window.UDPresentations?.recordFor?.(u.id,l.cfg.id));
 const phaseItems=phases.map((p,i)=>`<button class="classroom-phase ${i===0?'active':''}" data-classroom-phase="${i}" data-duration="${p.duration}"><span class="classroom-phase-time">${esc(String(p.start).padStart(2,'0'))}–${esc(String(p.end).padStart(2,'0'))}</span><span><strong>${esc(p.name)}</strong><small>${esc(p.material||p.students||'')}</small></span></button>`).join('');
 const phaseDetails=phases.map((p,i)=>`<section class="classroom-phase-detail ${i===0?'active':''}" data-classroom-detail="${i}"><span class="eyebrow">Phase ${i+1} · ${p.start}–${p.end} Minuten</span><h2>${esc(p.name)}</h2><div class="classroom-detail-grid"><div><strong>Lehrkraft</strong><p>${esc(p.teacher||'—')}</p></div><div><strong>Schüleraktivität</strong><p>${esc(p.students||'—')}</p></div><div><strong>Material / Sozialform</strong><p>${esc(p.material||'—')}</p></div><div><strong>Didaktischer Hinweis</strong><p>${esc(p.note||'—')}</p></div></div></section>`).join('');
 return `<main class="classroom-stage" data-classroom-unit="${esc(u.id)}" data-classroom-lesson="${esc(l.cfg.id)}"><header class="classroom-header"><div><span class="eyebrow">Unterrichtsmodus · ${esc(u.manifest.title)} · Stunde ${esc(l.ref.number)}</span><h1>${esc(l.ref.title)}</h1><p>${esc(l.cfg.subtitle||'')} · geplant: ${esc(l.ref.duration)} Minuten</p></div><div class="classroom-header-actions"><button class="btn ghost" data-classroom-fullscreen>Vollbild</button><button class="btn secondary" data-route="imported-lesson/${encodeURIComponent(u.id)}/${encodeURIComponent(l.cfg.id)}">Unterricht beenden</button></div></header><div class="classroom-layout"><aside class="classroom-sidebar"><div class="classroom-timer-card"><span>Verbleibende Phasenzeit</span><strong id="classroomTimer">${String(phases[0].duration).padStart(2,'0')}:00</strong><div class="classroom-timer-actions"><button class="mini-btn primary" data-classroom-timer="toggle">Start</button><button class="mini-btn" data-classroom-timer="plus">+1 Min.</button><button class="mini-btn" data-classroom-timer="reset">Reset</button></div></div><div class="classroom-phase-list">${phaseItems}</div></aside><section class="classroom-main"><div class="classroom-toolbar"><button class="classroom-tool ${hasPresentation?'ready':''}" ${hasPresentation?`data-route="presentation/${encodeURIComponent(u.id)}/${encodeURIComponent(l.cfg.id)}"`:'disabled'}><span>▶</span><strong>Präsentation</strong><small>${hasPresentation?'Starten':'Nicht hinterlegt'}</small></button><button class="classroom-tool" data-route="imported-lesson/${encodeURIComponent(u.id)}/${encodeURIComponent(l.cfg.id)}/materials"><span>▤</span><strong>Materialien</strong><small>Arbeitsblatt · Lösung · Sicherung</small></button><button class="classroom-tool" data-route="imported-lesson/${encodeURIComponent(u.id)}/${encodeURIComponent(l.cfg.id)}/help"><span>?</span><strong>Hilfen</strong><small>Scaffolding und Minimalfahrplan</small></button><button class="classroom-tool" data-route="imported-lesson/${encodeURIComponent(u.id)}/${encodeURIComponent(l.cfg.id)}/sequence"><span>≡</span><strong>Verlaufsplan</strong><small>Vollständige Planung</small></button></div><div class="classroom-current">${phaseDetails}</div><details class="classroom-emergency"><summary>⚠ Zeit wird knapp · Notausstieg öffnen</summary><div class="classroom-emergency-grid"><div><strong>Notausstieg</strong><p>${esc(fallback.notausstieg)}</p></div><div><strong>Minimalfahrplan</strong><p>${esc(fallback.minimal)}</p></div></div></details><div class="classroom-bottom-actions"><button class="btn ghost" data-classroom-prev>← Vorherige Phase</button><div id="classroomPhaseStatus">Phase 1 von ${phases.length}</div><button class="btn primary" data-classroom-next>Nächste Phase →</button></div></section></div></main>`
}
function bindClassroom(root){const stage=root.querySelector('.classroom-stage');if(!stage)return;const phases=[...stage.querySelectorAll('[data-classroom-phase]')],details=[...stage.querySelectorAll('[data-classroom-detail]')],timer=stage.querySelector('#classroomTimer'),status=stage.querySelector('#classroomPhaseStatus');let index=Math.max(0,Number(sessionStorage.getItem(`ud-classroom-phase:${stage.dataset.classroomUnit}:${stage.dataset.classroomLesson}`)||0));if(index>=phases.length)index=0;let remaining=Number(phases[index]?.dataset.duration||1)*60,running=false,handle=null;
 const format=()=>`${String(Math.max(0,Math.floor(remaining/60))).padStart(2,'0')}:${String(Math.max(0,remaining%60)).padStart(2,'0')}`;const paint=()=>{if(timer)timer.textContent=format();timer?.classList.toggle('warning',remaining<=120);timer?.classList.toggle('expired',remaining<=0)};
 const stop=()=>{running=false;if(handle){clearInterval(handle);handle=null}const b=stage.querySelector('[data-classroom-timer="toggle"]');if(b)b.textContent='Start'};
 const activate=i=>{stop();index=Math.min(Math.max(0,i),phases.length-1);phases.forEach((x,n)=>x.classList.toggle('active',n===index));details.forEach((x,n)=>x.classList.toggle('active',n===index));remaining=Number(phases[index]?.dataset.duration||1)*60;sessionStorage.setItem(`ud-classroom-phase:${stage.dataset.classroomUnit}:${stage.dataset.classroomLesson}`,String(index));if(status)status.textContent=`Phase ${index+1} von ${phases.length}`;paint()};
 phases.forEach((p,i)=>p.addEventListener('click',()=>activate(i)));stage.querySelector('[data-classroom-next]')?.addEventListener('click',()=>activate(index+1));stage.querySelector('[data-classroom-prev]')?.addEventListener('click',()=>activate(index-1));stage.querySelector('[data-classroom-timer="toggle"]')?.addEventListener('click',e=>{if(running){stop();return}running=true;e.currentTarget.textContent='Pause';handle=setInterval(()=>{remaining-=1;paint();if(remaining<=0)stop()},1000)});stage.querySelector('[data-classroom-timer="plus"]')?.addEventListener('click',()=>{remaining+=60;paint()});stage.querySelector('[data-classroom-timer="reset"]')?.addEventListener('click',()=>activate(index));stage.querySelector('[data-classroom-fullscreen]')?.addEventListener('click',async()=>{try{if(document.fullscreenElement)await document.exitFullscreen();else await stage.requestFullscreen?.()}catch(e){console.error(e)}});activate(index)
}

