function materialsView(u,l,h){const d=l.materials,worksheet=urlFor(u.id,d.worksheet),solution=urlFor(u.id,d.solution),board=urlFor(u.id,d.board);return h.shell(`<div class="content-header"><div><span class="eyebrow">Unterrichtsmaterial</span><h1>Arbeitsblatt + Musterlösung</h1><p class="content-intro">Arbeitsblatt, Lösung und Sicherung bleiben als eigenständige Druckdokumente erhalten.</p></div><button class="back-btn" data-route="imported-lesson/${encodeURIComponent(u.id)}/${encodeURIComponent(l.cfg.id)}">← Stundenübersicht</button></div><div class="material-toolbar no-print"><div class="tab-list"><button class="tab-button active" data-tab="worksheet">Arbeitsblatt</button><button class="tab-button" data-tab="solution">Musterlösung</button><button class="tab-button" data-tab="reveal">Sicherung</button></div><div class="hero-actions"><button class="btn secondary" data-print-frame="frame-worksheet">Arbeitsblatt drucken</button><button class="btn secondary" data-print-frame="frame-solution">Musterlösung drucken</button></div></div><div id="panel-worksheet" class="tab-panel active">${h.documentFrame('frame-worksheet',worksheet,'Arbeitsblatt · Druckansicht')}</div><div id="panel-solution" class="tab-panel">${h.documentFrame('frame-solution',solution,'Musterlösung · Druckansicht')}</div><div id="panel-reveal" class="tab-panel"><div class="board-controls no-print"><div><strong>Interaktive Sicherung</strong><span>Einzelne Lösungsflächen im Blatt auf- und zudecken.</span></div><div><button class="btn ghost" data-board-action="show">Alle Lösungen zeigen</button><button class="btn secondary" data-board-action="hide">Alle Lösungen verdecken</button></div></div>${h.documentFrame('frame-board',board,'Sicherung · Lösungen direkt im Blatt aufdecken')}</div>`,crumbs(u,l).concat([{label:'Arbeitsblatt + Musterlösung'}]))}
