async function sample(){const r=await fetch('import/04_Sprachlicher_Feinschliff.unterricht.zip');if(!r.ok)throw new Error('Referenzpaket konnte nicht geladen werden. Nutze den lokalen Starter.');return new File([await r.blob()],'04_Sprachlicher_Feinschliff.unterricht.zip',{type:'application/zip'})}

function u16(v){const b=new Uint8Array(2);new DataView(b.buffer).setUint16(0,v,true);return b}
function u32(v){const b=new Uint8Array(4);new DataView(b.buffer).setUint32(0,v>>>0,true);return b}
function concat(parts){const total=parts.reduce((n,p)=>n+p.length,0),out=new Uint8Array(total);let o=0;for(const p of parts){out.set(p,o);o+=p.length}return out}
function dosTimeDate(){const d=new Date(),time=((d.getHours()&31)<<11)|((d.getMinutes()&63)<<5)|((Math.floor(d.getSeconds()/2))&31),date=(((d.getFullYear()-1980)&127)<<9)|(((d.getMonth()+1)&15)<<5)|(d.getDate()&31);return{time,date}}
async function buildZipBlob(files){
 const locals=[],centrals=[];let offset=0;const td=dosTimeDate();
 for(const rel of Object.keys(files).sort()){
  if(!safePath(rel))throw new Error('Unsicherer ZIP-Pfad: '+rel);
  const name=encoder.encode(rel),source=files[rel],blob=source instanceof Blob?source:new Blob([source]),data=new Uint8Array(await blob.arrayBuffer()),crc=crc32(data);
  const local=concat([u32(0x04034b50),u16(20),u16(0x0800),u16(0),u16(td.time),u16(td.date),u32(crc),u32(data.length),u32(data.length),u16(name.length),u16(0),name,data]);locals.push(local);
  const central=concat([u32(0x02014b50),u16(20),u16(20),u16(0x0800),u16(0),u16(td.time),u16(td.date),u32(crc),u32(data.length),u32(data.length),u16(name.length),u16(0),u16(0),u16(0),u16(0),u32(0),u32(offset),name]);centrals.push(central);offset+=local.length
 }
 const centralBlob=concat(centrals),eocd=concat([u32(0x06054b50),u16(0),u16(0),u16(centrals.length),u16(centrals.length),u32(centralBlob.length),u32(offset),u16(0)]);
 return new Blob([concat(locals),centralBlob,eocd],{type:'application/zip'})
}
async function buildPackageBlob(record){
 const root=slug(record.manifest.navigation?.unit||record.manifest.title)+'/',files={};
 for(const [rel,blob] of Object.entries(record.files||{}))files[root+rel]=blob;
 files[root+'manifest.json']=new Blob([JSON.stringify(record.manifest,null,2)],{type:'application/json'});
 return buildZipBlob(files)
}
function downloadBlob(blob,name){const url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=name;document.body.appendChild(a);a.click();a.remove();setTimeout(()=>URL.revokeObjectURL(url),1500)}
async function exportUnit(id){const u=state.byId.get(id);if(!u)throw new Error('Einheit nicht gefunden.');const blob=await buildPackageBlob(u);downloadBlob(blob,`${slug(u.manifest.navigation?.unit||u.manifest.title)}.unterricht.zip`)}

async function createLibraryBackupBlob(){
 const root=`Unterrichtsbibliothek_${stamp()}/`,files={},unitEntries=[],recoveryEntries=[];
 let i=0;
 for(const u of state.units){
  const blob=await buildPackageBlob(u),bytes=new Uint8Array(await blob.arrayBuffer()),path=`units/${String(++i).padStart(3,'0')}_${slug(u.manifest.title)}.unterricht.zip`;
  files[root+path]=blob;unitEntries.push({id:u.id,title:u.manifest.title,version:u.manifest.version,path,sha256:await sha256(bytes),installedAt:u.installedAt||null,updatedAt:u.updatedAt||null})
 }
 i=0;
 for(const b of state.backups){
  const blob=await buildPackageBlob(b.unit),bytes=new Uint8Array(await blob.arrayBuffer()),path=`recovery/${String(++i).padStart(3,'0')}_${slug(b.title)}.unterricht.zip`;
  files[root+path]=blob;recoveryEntries.push({backupId:b.backupId,unitId:b.unitId,title:b.title,version:b.version,reason:b.reason,createdAt:b.createdAt,path,sha256:await sha256(bytes)})
 }
 const presentations=await window.UDPresentations?.appendBackup(files,root)||[];
 const settings=collectSettings(),settingsPath='settings.json';
 files[root+settingsPath]=new Blob([JSON.stringify({schemaVersion:'1.0',settings},null,2)],{type:'application/json'});
 const manifest={schemaVersion:'1.0',packageType:'unterricht-library-backup',createdAt:nowIso(),appVersion:window.UD?.catalog?.version||'1.3.0',database:DB_NAME,units:unitEntries,recoveryPoints:recoveryEntries,settings:settingsPath,presentations,summary:{units:unitEntries.length,recoveryPoints:recoveryEntries.length,presentations:presentations.length,settings:Object.keys(settings).length}};
 files[root+'bibliothek.json']=new Blob([JSON.stringify(manifest,null,2)],{type:'application/json'});
 return{blob:await buildZipBlob(files),manifest}
}
async function exportLibraryBackup(){const built=await createLibraryBackupBlob();downloadBlob(built.blob,`Unterrichtsbibliothek_Backup_${stamp()}.unterrichtsbibliothek.zip`);return built.manifest}

async function parseLibraryBackup(file){
 if(!file||!file.name.toLowerCase().endsWith('.zip'))throw new Error('Bitte eine .unterrichtsbibliothek.zip-Datei auswählen.');
 const zip=await ZipArchive.fromFile(file),manifests=zip.names().filter(n=>n.endsWith('bibliothek.json')&&!n.endsWith('/'));
 if(manifests.length!==1)throw new Error('Die Sicherung muss genau eine bibliothek.json enthalten.');
 const manifestPath=manifests[0],root=manifestPath.slice(0,-'bibliothek.json'.length),m=JSON.parse(await zip.text(manifestPath));
 if(m.schemaVersion!=='1.0'||m.packageType!=='unterricht-library-backup')throw new Error('Die Datei ist keine Unterrichtsbibliothek-Sicherung Version 1.0.');
 if(!Array.isArray(m.units)||!Array.isArray(m.recoveryPoints))throw new Error('Die Bibliothekslisten sind ungültig.');
 const seen=new Set(),units=[],backups=[],warnings=[];
 async function readUnit(entry,label){
  if(!entry||!safePath(entry.path)||!zip.has(root+entry.path))throw new Error(`${label}: Paketdatei fehlt oder Pfad ist unsicher.`);
  const bytes=await zip.bytes(root+entry.path),digest=await sha256(bytes);
  if(entry.sha256&&digest.toLowerCase()!==String(entry.sha256).toLowerCase())throw new Error(`${label}: Prüfsumme stimmt nicht.`);
  const parsed=await parsePackage(new File([bytes],entry.path.split('/').pop(),{type:'application/zip'}));return parsed.record
 }
 for(const entry of m.units){if(!entry.id||seen.has(entry.id))throw new Error('Doppelte oder fehlende Einheiten-ID in der Sicherung.');seen.add(entry.id);const record=await readUnit(entry,entry.title||entry.id);record.installedAt=entry.installedAt||record.installedAt;record.updatedAt=entry.updatedAt||record.updatedAt;units.push(record)}
 for(const entry of m.recoveryPoints){const record=await readUnit(entry,entry.title||entry.unitId||'Wiederherstellungspunkt');backups.push({backupId:entry.backupId||`restored::${Date.now()}::${backups.length}`,unitId:entry.unitId||record.id,title:entry.title||record.manifest.title,version:entry.version||record.manifest.version,reason:entry.reason||'Aus Bibliothekssicherung',createdAt:entry.createdAt||m.createdAt,unit:record})}
 let settings={};
 if(m.settings){if(!safePath(m.settings)||!zip.has(root+m.settings))warnings.push('Die Einstellungsdatei fehlt.');else{const cfg=JSON.parse(await zip.text(root+m.settings));if(cfg?.settings&&typeof cfg.settings==='object')settings=cfg.settings;else warnings.push('Die Einstellungsdatei ist ungültig.')}}
 const presentations=await window.UDPresentations?.readBackup(zip,root,m)||[];
 return{manifest:m,units,backups,presentations,settings,warnings,sourceName:file.name}
}
async function prepareLibraryRestore(file){state.pendingLibraryRestore=await parseLibraryBackup(file);state.lastMessage={type:'ok',text:'Bibliothekssicherung wurde geprüft. Bitte die Wiederherstellungsart bestätigen.'}}
function normalizedRestoredBackup(b,index){return{...b,backupId:`restored::${Date.now()}::${index}::${Math.random().toString(36).slice(2,8)}`,reason:`${b.reason||'Wiederherstellungspunkt'} · aus Bibliothekssicherung`,unit:b.unit}}
async function commitLibraryRestore(mode){
 const pending=state.pendingLibraryRestore;if(!pending)throw new Error('Keine geprüfte Bibliothekssicherung vorhanden.');
 if(!['replace','merge'].includes(mode))throw new Error('Unbekannte Wiederherstellungsart.');
 const current=new Map(state.units.map(u=>[u.id,u]));
 await transaction([UNIT_STORE,BACKUP_STORE,'presentations','presentationBackups'],'readwrite',s=>{
  if(mode==='replace'){s[UNIT_STORE].clear();s[BACKUP_STORE].clear();s.presentations.clear();s.presentationBackups.clear();for(const u of state.units)s[BACKUP_STORE].put(makeBackup(u,'Vor vollständiger Bibliotheks-Wiederherstellung'))}
  for(const u of pending.units){const existing=current.get(u.id);if(mode==='merge'&&existing)s[BACKUP_STORE].put(makeBackup(existing,'Vor Zusammenführung einer Bibliothekssicherung'));s[UNIT_STORE].put(u)}
  pending.backups.forEach((b,index)=>s[BACKUP_STORE].put(normalizedRestoredBackup(b,index)));
  for(const p of (pending.presentations||[]))s.presentations.put(p)
 });
 applySettings(pending.settings,true);state.acceptance=loadAcceptance();state.pendingLibraryRestore=null;await refreshAll();await window.UDPresentations?.reload();for(const u of state.units)setAccepted(u.id,true);await refreshStorageStatus();
 state.lastMessage={type:'ok',text:mode==='replace'?'Die Bibliothek wurde vollständig wiederhergestellt. Der vorherige aktive Bestand ist als Wiederherstellungspunkt gesichert.':'Die Sicherung wurde mit der bestehenden Bibliothek zusammengeführt.'}
}

async function prepare(file){const parsed=await parsePackage(file);const existing=state.byId.get(parsed.record.id);state.pendingImport={...parsed,conflict:existing?{id:existing.id,title:existing.manifest.title,version:existing.manifest.version,relation:versionRelation(parsed.record.manifest.version,existing.manifest.version)}:null};state.lastMessage={type:'ok',text:'Paket wurde vollständig geprüft. Bitte die Importvorschau bestätigen.'}}
function findBackup(id){return state.backups.find(b=>b.backupId===id)}
function bind(root,go,rerender){
 bindClassroom(root);
 const input=root.querySelector('#dynamicImportInput'),status=root.querySelector('#dynamicImportStatus');const show=t=>{if(status)status.textContent=t};
 const run=async file=>{if(!file)return;show('Paket wird geprüft …');try{await prepare(file);rerender()}catch(e){console.error(e);state.pendingImport=null;state.lastMessage={type:'error',text:'Importprüfung fehlgeschlagen: '+e.message};rerender()}};
 root.querySelector('#dynamicImportBtn')?.addEventListener('click',()=>input?.click());
 input?.addEventListener('change',()=>run(input.files?.[0]));
 root.querySelector('#dynamicSampleBtn')?.addEventListener('click',async()=>{show('Referenzpaket wird geladen …');try{await run(await sample())}catch(e){state.lastMessage={type:'error',text:'Referenzpaket konnte nicht geladen werden: '+e.message};rerender()}});
 root.querySelectorAll('[data-migrate-package]').forEach(b=>b.addEventListener('click',async()=>{show('Migrationspaket wird geladen …');try{await run(await bundledFile(b.dataset.migratePackage))}catch(e){state.lastMessage={type:'error',text:'Migrationspaket konnte nicht geladen werden: '+e.message};rerender()}}));
 root.querySelector('[data-import-cancel]')?.addEventListener('click',()=>{state.pendingImport=null;state.lastMessage={type:'ok',text:'Import wurde abgebrochen. Es wurden keine Daten verändert.'};rerender()});
 root.querySelectorAll('[data-import-confirm]').forEach(b=>b.addEventListener('click',async()=>{b.disabled=true;try{await confirmPending(b.dataset.importConfirm);rerender()}catch(e){state.lastMessage={type:'error',text:'Import konnte nicht abgeschlossen werden: '+e.message};rerender()}}));
 root.querySelectorAll('[data-export-unit]').forEach(b=>b.addEventListener('click',async()=>{try{await exportUnit(b.dataset.exportUnit)}catch(e){state.lastMessage={type:'error',text:'Export fehlgeschlagen: '+e.message};rerender()}}));
 root.querySelectorAll('[data-remove-unit]').forEach(b=>b.addEventListener('click',async()=>{const u=state.byId.get(b.dataset.removeUnit);if(!u)return;if(!confirm(`„${u.manifest.title}“ entfernen? Vorher wird automatisch ein Wiederherstellungspunkt angelegt.`))return;try{await commitDelete(u);setAccepted(u.id,false);await refreshAll();state.lastMessage={type:'ok',text:`„${u.manifest.title}“ wurde entfernt. Eine Sicherung steht zur Wiederherstellung bereit.`};go('import-library')}catch(e){state.lastMessage={type:'error',text:'Entfernen fehlgeschlagen: '+e.message};rerender()}}));
 root.querySelectorAll('[data-restore-backup]').forEach(b=>b.addEventListener('click',async()=>{const backup=findBackup(b.dataset.restoreBackup);if(!backup)return;if(!confirm(`Sicherung „${backup.title}“ (Version ${backup.version}) wiederherstellen?`))return;try{await commitRestore(backup);await refreshAll();state.lastMessage={type:'ok',text:`„${backup.title}“ wurde aus dem Wiederherstellungspunkt geladen.`};rerender()}catch(e){state.lastMessage={type:'error',text:'Wiederherstellung fehlgeschlagen: '+e.message};rerender()}}));
 root.querySelectorAll('[data-acceptance-unit]').forEach(b=>b.addEventListener('click',()=>{const id=b.dataset.acceptanceUnit,value=b.dataset.acceptanceValue==='1',u=state.byId.get(id);if(!u)return;const report=acceptanceReport(u);if(value&&!report.ok){state.lastMessage={type:'error',text:'Das Einheitspaket ist unvollständig und kann nicht aktiviert werden.'};rerender();return}setAccepted(id,value);state.lastMessage={type:'ok',text:value?`„${u.manifest.title}“ wurde als aktive Einheit markiert.`:`Die Freigabe für „${u.manifest.title}“ wurde zurückgesetzt.`};rerender()}));
 root.querySelectorAll('[data-delete-backup]').forEach(b=>b.addEventListener('click',async()=>{if(!confirm('Diesen Wiederherstellungspunkt endgültig löschen?'))return;await deleteBackup(b.dataset.deleteBackup);await refreshAll();state.lastMessage={type:'ok',text:'Wiederherstellungspunkt wurde gelöscht.'};rerender()}));
 const libraryInput=root.querySelector('#libraryRestoreInput'),libraryStatus=root.querySelector('#libraryBackupStatus');
 root.querySelector('#libraryBackupExportBtn')?.addEventListener('click',async()=>{const b=root.querySelector('#libraryBackupExportBtn');if(b)b.disabled=true;if(libraryStatus)libraryStatus.textContent='Sicherung wird erstellt …';try{const m=await exportLibraryBackup();state.lastMessage={type:'ok',text:`Bibliothekssicherung mit ${m.units.length} Einheit(en) wurde erstellt.`};rerender()}catch(e){state.lastMessage={type:'error',text:'Bibliothekssicherung fehlgeschlagen: '+e.message};rerender()}});
 root.querySelector('#libraryRestoreBtn')?.addEventListener('click',()=>libraryInput?.click());
 libraryInput?.addEventListener('change',async()=>{const file=libraryInput.files?.[0];if(!file)return;if(libraryStatus)libraryStatus.textContent='Bibliothekssicherung wird geprüft …';try{await prepareLibraryRestore(file);rerender()}catch(e){state.pendingLibraryRestore=null;state.lastMessage={type:'error',text:'Wiederherstellungsprüfung fehlgeschlagen: '+e.message};rerender()}});
 root.querySelector('[data-library-restore-cancel]')?.addEventListener('click',()=>{state.pendingLibraryRestore=null;state.lastMessage={type:'ok',text:'Wiederherstellung wurde abgebrochen. Es wurden keine Daten verändert.'};rerender()});
 root.querySelectorAll('[data-library-restore]').forEach(b=>b.addEventListener('click',async()=>{b.disabled=true;try{await commitLibraryRestore(b.dataset.libraryRestore);rerender()}catch(e){state.lastMessage={type:'error',text:'Bibliothek konnte nicht wiederhergestellt werden: '+e.message};rerender()}}));
 root.querySelector('#persistStorageBtn')?.addEventListener('click',async()=>{try{const granted=await requestPersistentStorage();state.lastMessage={type:granted?'ok':'error',text:granted?'Der Browser schützt die lokale Unterrichtsbibliothek nun vor automatischer Speicherbereinigung.':'Der Browser hat dauerhaften Speicher nicht freigegeben. Regelmäßige Bibliothekssicherungen bleiben erforderlich.'};rerender()}catch(e){state.lastMessage={type:'error',text:e.message};rerender()}});
 root.querySelector('#dynamicClearBtn')?.addEventListener('click',async()=>{if(!confirm('Unterrichtsbibliothek leeren? Für jede Einheit wird vorher ein Wiederherstellungspunkt angelegt.'))return;try{await commitClear();await refreshAll();state.pendingImport=null;state.lastMessage={type:'ok',text:'Die Unterrichtsbibliothek wurde geleert. Wiederherstellungspunkte wurden angelegt.'};rerender()}catch(e){state.lastMessage={type:'error',text:'Bibliothek konnte nicht geleert werden: '+e.message};rerender()}})
}
function renderRoute(p,h){if(p[0]==='classroom')return classroomView(p[1],p[2],h);if(p[0]==='import-library')return libraryView(h);if(p[0]==='library-area')return dynamicAreaView(p[1],h);if(p[0]==='library-subject')return dynamicSubjectView(p[1],p[2],h);if(p[0]==='library-level')return dynamicLevelView(p[1],p[2],p[3],h);if(p[0]==='imported-unit')return unitView(p[1],h);if(p[0]==='imported-lesson'&&p[3])return sectionView(p[1],p[2],p[3],h);if(p[0]==='imported-lesson')return lessonView(p[1],p[2],h);return null}

window.UDDynamicLibrary={state,init,reload:refreshAll,searchIndex,homeCard,sidebar,renderRoute,bind,prepare,parsePackage,exportUnit,exportLibraryBackup,prepareLibraryRestore,unitsAt,mergedUnits,extraLevels,extraSubjects,extraAreas,isAccepted,regularContext,acceptanceReport,_test:{buildPackageBlob,buildZipBlob,createLibraryBackupBlob,parseLibraryBackup,crc32}};
